712	    /// Steals no more than `limit` of tasks and pushes them into another worker.
713	    ///
714	    /// How many tasks exactly will be stolen is not specified. That said, this method will try to
715	    /// steal around half of the tasks in the queue, but also not more than the given limit.
716	    ///
717	    /// # Examples
718	    ///
719	    /// ```
720	    /// use crossbeam_deque::Worker;
721	    ///
722	    /// let w1 = Worker::new_fifo();
723	    /// w1.push(1);
724	    /// w1.push(2);
725	    /// w1.push(3);
726	    /// w1.push(4);
727	    /// w1.push(5);
728	    /// w1.push(6);
729	    ///
730	    /// let s = w1.stealer();
731	    /// let w2 = Worker::new_fifo();
732	    ///
733	    /// let _ = s.steal_batch_with_limit(&w2, 2);
734	    /// assert_eq!(w2.pop(), Some(1));
735	    /// assert_eq!(w2.pop(), Some(2));
736	    /// assert_eq!(w2.pop(), None);
737	    ///
738	    /// w1.push(7);
739	    /// w1.push(8);
740	    /// // Setting a large limit does not guarantee that all elements will be popped. In this case,
741	    /// // half of the elements are currently popped, but the number of popped elements is considered
742	    /// // an implementation detail that may be changed in the future.
743	    /// let _ = s.steal_batch_with_limit(&w2, usize::MAX);
744	    /// assert_eq!(w2.len(), 3);
745	    /// ```
746	    pub fn steal_batch_with_limit(&self, dest: &Worker<T>, limit: usize) -> Steal<()> {
747	        assert!(limit > 0);
748	        if Arc::ptr_eq(&self.inner, &dest.inner) {
749	            if dest.is_empty() {
750	                return Steal::Empty;
751	            } else {
752	                return Steal::Success(());
753	            }
754	        }
755	
756	        // Load the front index.
757	        let mut f = self.inner.front.load(Ordering::Acquire);
758	
759	        // A SeqCst fence is needed here.
760	        //
761	        // If the current thread is already pinned (reentrantly), we must manually issue the
762	        // fence. Otherwise, the following pinning will issue the fence anyway, so we don't
763	        // have to.
764	        if epoch::is_pinned() {
765	            atomic::fence(Ordering::SeqCst);
766	        }
767	
768	        let guard = &epoch::pin();
769	
770	        // Load the back index.
771	        let b = self.inner.back.load(Ordering::Acquire);
772	
773	        // Is the queue empty?
774	        let len = b.wrapping_sub(f);
775	        if len <= 0 {
776	            return Steal::Empty;
777	        }
778	
779	        // Reserve capacity for the stolen batch.
780	        let batch_size = cmp::min((len as usize).div_ceil(2), limit);
781	        dest.reserve(batch_size);
782	        let mut batch_size = batch_size as isize;
783	
784	        // Get the destination buffer and back index.
785	        let dest_buffer = dest.buffer.get();
786	        let mut dest_b = dest.inner.back.load(Ordering::Relaxed);
787	
788	        // Load the buffer.
789	        let buffer = self.inner.buffer.load(Ordering::Acquire, guard);
790	
791	        match self.flavor {
792	            // Steal a batch of tasks from the front at once.
793	            Flavor::Fifo => {
794	                // Copy the batch from the source to the destination buffer.
795	                match dest.flavor {
796	                    Flavor::Fifo => {
797	                        for i in 0..batch_size {
798	                            unsafe {
799	                                let task = buffer.deref().read(f.wrapping_add(i));
800	                                dest_buffer.write(dest_b.wrapping_add(i), task);
801	                            }
802	                        }
803	                    }
804	                    Flavor::Lifo => {
805	                        for i in 0..batch_size {
806	                            unsafe {
807	                                let task = buffer.deref().read(f.wrapping_add(i));
808	                                dest_buffer.write(dest_b.wrapping_add(batch_size - 1 - i), task);
809	                            }
810	                        }
811	                    }
812	                }
813	
814	                // Try incrementing the front index to steal the batch.
815	                // If the buffer has been swapped or the increment fails, we retry.
816	                if self.inner.buffer.load(Ordering::Acquire, guard) != buffer
817	                    || self
818	                        .inner
819	                        .front
820	                        .compare_exchange(
821	                            f,
822	                            f.wrapping_add(batch_size),
823	                            Ordering::SeqCst,
824	                            Ordering::Relaxed,
825	                        )
826	                        .is_err()
827	                {
828	                    return Steal::Retry;
829	                }
830	
831	                dest_b = dest_b.wrapping_add(batch_size);
832	            }
833	
834	            // Steal a batch of tasks from the front one by one.
835	            Flavor::Lifo => {
836	                // This loop may modify the batch_size, which triggers a clippy lint warning.
837	                // Use a new variable to avoid the warning, and to make it clear we aren't
838	                // modifying the loop exit condition during iteration.
839	                let original_batch_size = batch_size;
840	
841	                for i in 0..original_batch_size {
842	                    // If this is not the first steal, check whether the queue is empty.
843	                    if i > 0 {
844	                        // We've already got the current front index. Now execute the fence to
845	                        // synchronize with other threads.
846	                        atomic::fence(Ordering::SeqCst);
847	
848	                        // Load the back index.
849	                        let b = self.inner.back.load(Ordering::Acquire);
850	
851	                        // Is the queue empty?
852	                        if b.wrapping_sub(f) <= 0 {
853	                            batch_size = i;
854	                            break;
855	                        }
856	                    }
857	
858	                    // Read the task at the front.
859	                    let task = unsafe { buffer.deref().read(f) };
860	
861	                    // Try incrementing the front index to steal the task.
862	                    // If the buffer has been swapped or the increment fails, we retry.
863	                    if self.inner.buffer.load(Ordering::Acquire, guard) != buffer
864	                        || self
865	                            .inner
866	                            .front
867	                            .compare_exchange(
868	                                f,
869	                                f.wrapping_add(1),
870	                                Ordering::SeqCst,
871	                                Ordering::Relaxed,
872	                            )
873	                            .is_err()
874	                    {
875	                        // We didn't steal this task, forget it and break from the loop.
876	                        batch_size = i;
877	                        break;
878	                    }
879	
880	                    // Write the stolen task into the destination buffer.
881	                    unsafe {
882	                        dest_buffer.write(dest_b, task);
883	                    }
884	
885	                    // Move the source front index and the destination back index one step forward.
886	                    f = f.wrapping_add(1);
887	                    dest_b = dest_b.wrapping_add(1);
888	                }
889	
890	                // If we didn't steal anything, the operation needs to be retried.
891	                if batch_size == 0 {
892	                    return Steal::Retry;
893	                }
894	
895	                // If stealing into a FIFO queue, stolen tasks need to be reversed.
896	                if dest.flavor == Flavor::Fifo {
897	                    for i in 0..batch_size / 2 {
898	                        unsafe {
899	                            let i1 = dest_b.wrapping_sub(batch_size - i);
900	                            let i2 = dest_b.wrapping_sub(i + 1);
901	                            let t1 = dest_buffer.read(i1);
902	                            let t2 = dest_buffer.read(i2);
903	                            dest_buffer.write(i1, t2);
904	                            dest_buffer.write(i2, t1);
905	                        }
906	                    }
907	                }
908	            }
909	        }
910	
911	        // ThreadSanitizer does not understand fences, so we omit fence and do store with Release ordering.
912	        #[cfg(not(crossbeam_sanitize_thread))]
913	        atomic::fence(Ordering::Release);
914	        let store_order = if cfg!(crossbeam_sanitize_thread) {
915	            Ordering::Release
916	        } else {
917	            Ordering::Relaxed
918	        };
919	
920	        // Update the back index in the destination queue.
921	        dest.inner.back.store(dest_b, store_order);
922	
923	        // Return with success.
924	        Steal::Success(())
925	    }
