1196	// Bits indicating the state of a slot:
1197	// * If a task has been written into the slot, `WRITE` is set.
1198	// * If a task has been read from the slot, `READ` is set.
1199	// * If the block is being destroyed, `DESTROY` is set.
1200	const WRITE: usize = 1;
1201	const READ: usize = 2;
1202	const DESTROY: usize = 4;
1203	
1204	// Each block covers one "lap" of indices.
1205	const LAP: usize = 64;
1206	// The maximum number of values a block can hold.
1207	const BLOCK_CAP: usize = LAP - 1;
1208	// How many lower bits are reserved for metadata.
1209	const SHIFT: usize = 1;
1210	// Indicates that the block is not the last one.
1211	const HAS_NEXT: usize = 1;
1212	
1213	/// A slot in a block.
1214	struct Slot<T> {
1215	    /// The task.
1216	    task: UnsafeCell<MaybeUninit<T>>,
1217	
1218	    /// The state of the slot.
1219	    state: AtomicUsize,
1220	}
1221	
1222	impl<T> Slot<T> {
1223	    /// Waits until a task is written into the slot.
1224	    fn wait_write(&self) {
1225	        let backoff = Backoff::new();
1226	        while self.state.load(Ordering::Acquire) & WRITE == 0 {
1227	            backoff.snooze();
1228	        }
1229	    }
1230	}
