1243	impl<T> Block<T> {
1244	    const LAYOUT: Layout = {
1245	        let layout = Layout::new::<Self>();
1246	        assert!(
1247	            layout.size() != 0,
1248	            "Block should never be zero-sized, as it has an AtomicPtr field"
1249	        );
1250	        layout
1251	    };
1252	
1253	    /// Creates an empty block.
1254	    fn new() -> Box<Self> {
1255	        // unsafe { Box::new_zeroed().assume_init() } requires Rust 1.92
1256	        match Global.allocate_zeroed(Self::LAYOUT) {
1257	            Some(ptr) => {
1258	                // SAFETY: This is safe because:
1259	                //  [1] `Block::next` (AtomicPtr) may be safely zero initialized.
1260	                //  [2] `Block::slots` (Array) may be safely zero initialized because of [3, 4].
1261	                //  [3] `Slot::task` (UnsafeCell) may be safely zero initialized because it
1262	                //       holds a MaybeUninit.
1263	                //  [4] `Slot::state` (AtomicUsize) may be safely zero initialized.
1264	                unsafe { Box::from_raw(ptr.as_ptr().cast()) }
1265	            }
1266	            // Handle allocation failure
1267	            None => handle_alloc_error(Self::LAYOUT),
1268	        }
1269	    }
