1283	    /// Sets the `DESTROY` bit in slots starting from `start` and destroys the block.
1284	    unsafe fn destroy(this: *mut Self, count: usize) {
1285	        // It is not necessary to set the `DESTROY` bit in the last slot because that slot has
1286	        // begun destruction of the block.
1287	        for i in (0..count).rev() {
1288	            let slot = unsafe { (*this).slots.get_unchecked(i) };
1289	
1290	            // Mark the `DESTROY` bit if a thread is still using the slot.
1291	            if slot.state.load(Ordering::Acquire) & READ == 0
1292	                && slot.state.fetch_or(DESTROY, Ordering::AcqRel) & READ == 0
1293	            {
1294	                // If a thread is still using the slot, it will continue destruction of the block.
1295	                return;
1296	            }
1297	        }
1298	
1299	        // No thread is using the block, now it is safe to destroy it.
1300	        drop(unsafe { Box::from_raw(this) });
1301	    }
1302	}
