1571	    /// steal around half of the tasks in the queue, but also not more than some constant limit.
1572	    ///
1573	    /// # Examples
1574	    ///
1575	    /// ```
1576	    /// # if option_env!("MIRI_FALLIBLE_WEAK_CAS").is_some() { return; } // see ci/miri.sh
1577	    /// use crossbeam_deque::{Injector, Worker};
1578	    ///
1579	    /// let q = Injector::new();
1580	    /// q.push(1);
1581	    /// q.push(2);
1582	    /// q.push(3);
1583	    /// q.push(4);
1584	    /// q.push(5);
1585	    /// q.push(6);
1586	    ///
1587	    /// let w = Worker::new_fifo();
1588	    /// let _ = q.steal_batch_with_limit(&w, 2);
1589	    /// assert_eq!(w.pop(), Some(1));
1590	    /// assert_eq!(w.pop(), Some(2));
1591	    /// assert_eq!(w.pop(), None);
1592	    ///
1593	    /// q.push(7);
1594	    /// q.push(8);
1595	    /// // Setting a large limit does not guarantee that all elements will be popped. In this case,
1596	    /// // half of the elements are currently popped, but the number of popped elements is considered
1597	    /// // an implementation detail that may be changed in the future.
1598	    /// let _ = q.steal_batch_with_limit(&w, usize::MAX);
1599	    /// assert_eq!(w.len(), 3);
1600	    /// ```
1601	    pub fn steal_batch_with_limit(&self, dest: &Worker<T>, limit: usize) -> Steal<()> {
1602	        assert!(limit > 0);
1603	        let mut head;
1604	        let mut block;
1605	        let mut offset;
1606	
1607	        let backoff = Backoff::new();
1608	        loop {
1609	            head = self.head.index.load(Ordering::Acquire);
1610	            block = self.head.block.load(Ordering::Acquire);
1611	
1612	            // Calculate the offset of the index into the block.
1613	            offset = (head >> SHIFT) % LAP;
1614	
1615	            // If we reached the end of the block, wait until the next one is installed.
1616	            if offset == BLOCK_CAP {
1617	                backoff.snooze();
1618	            } else {
1619	                break;
1620	            }
1621	        }
1622	
1623	        let mut new_head = head;
1624	        let advance;
1625	
1626	        if new_head & HAS_NEXT == 0 {
1627	            atomic::fence(Ordering::SeqCst);
1628	            let tail = self.tail.index.load(Ordering::Relaxed);
1629	
1630	            // If the tail equals the head, that means the queue is empty.
1631	            if head >> SHIFT == tail >> SHIFT {
1632	                return Steal::Empty;
1633	            }
1634	
1635	            // If head and tail are not in the same block, set `HAS_NEXT` in head. Also, calculate
1636	            // the right batch size to steal.
1637	            if (head >> SHIFT) / LAP != (tail >> SHIFT) / LAP {
1638	                new_head |= HAS_NEXT;
1639	                // We can steal all tasks till the end of the block.
1640	                advance = (BLOCK_CAP - offset).min(limit);
1641	            } else {
1642	                let len = (tail - head) >> SHIFT;
1643	                // Steal half of the available tasks.
1644	                advance = len.div_ceil(2).min(limit);
1645	            }
1646	        } else {
1647	            // We can steal all tasks till the end of the block.
1648	            advance = (BLOCK_CAP - offset).min(limit);
1649	        }
1650	
1651	        new_head += advance << SHIFT;
1652	        let new_offset = offset + advance;
1653	
1654	        // Try moving the head index forward.
1655	        if self
1656	            .head
1657	            .index
1658	            .compare_exchange_weak(head, new_head, Ordering::SeqCst, Ordering::Acquire)
1659	            .is_err()
1660	        {
1661	            return Steal::Retry;
1662	        }
1663	
1664	        // Reserve capacity for the stolen batch.
1665	        let batch_size = new_offset - offset;
1666	        dest.reserve(batch_size);
1667	
1668	        // Get the destination buffer and back index.
1669	        let dest_buffer = dest.buffer.get();
1670	        let dest_b = dest.inner.back.load(Ordering::Relaxed);
1671	
1672	        unsafe {
1673	            // If we've reached the end of the block, move to the next one.
1674	            if new_offset == BLOCK_CAP {
1675	                let next = (*block).wait_next();
1676	                let mut next_index = (new_head & !HAS_NEXT).wrapping_add(1 << SHIFT);
1677	                if !(*next).next.load(Ordering::Relaxed).is_null() {
1678	                    next_index |= HAS_NEXT;
1679	                }
1680	
1681	                self.head.block.store(next, Ordering::Release);
1682	                self.head.index.store(next_index, Ordering::Release);
1683	            }
1684	
1685	            // Copy values from the injector into the destination queue.
1686	            match dest.flavor {
1687	                Flavor::Fifo => {
1688	                    for i in 0..batch_size {
1689	                        // Read the task.
1690	                        let slot = (*block).slots.get_unchecked(offset + i);
1691	                        slot.wait_write();
1692	                        let task = slot.task.get().read();
1693	
1694	                        // Write it into the destination queue.
1695	                        dest_buffer.write(dest_b.wrapping_add(i as isize), task);
1696	                    }
1697	                }
1698	
1699	                Flavor::Lifo => {
1700	                    for i in 0..batch_size {
1701	                        // Read the task.
1702	                        let slot = (*block).slots.get_unchecked(offset + i);
1703	                        slot.wait_write();
1704	                        let task = slot.task.get().read();
1705	
1706	                        // Write it into the destination queue.
1707	                        dest_buffer.write(dest_b.wrapping_add((batch_size - 1 - i) as isize), task);
1708	                    }
1709	                }
1710	            }
1711	
1712	            // ThreadSanitizer does not understand fences, so we omit fence and do store with Release ordering.
1713	            #[cfg(not(crossbeam_sanitize_thread))]
1714	            atomic::fence(Ordering::Release);
1715	            let store_order = if cfg!(crossbeam_sanitize_thread) {
1716	                Ordering::Release
1717	            } else {
1718	                Ordering::Relaxed
1719	            };
1720	
1721	            // Update the back index in the destination queue.
1722	            dest.inner
1723	                .back
1724	                .store(dest_b.wrapping_add(batch_size as isize), store_order);
1725	
1726	            // Destroy the block if we've reached the end, or if another thread wanted to destroy
1727	            // but couldn't because we were busy reading from the slot.
1728	            if new_offset == BLOCK_CAP {
1729	                Block::destroy(block, offset);
1730	            } else {
1731	                for i in offset..new_offset {
1732	                    let slot = (*block).slots.get_unchecked(i);
1733	
1734	                    if slot.state.fetch_or(READ, Ordering::AcqRel) & DESTROY != 0 {
1735	                        Block::destroy(block, offset);
1736	                        break;
1737	                    }
1738	                }
1739	            }
1740	
1741	            Steal::Success(())
1742	        }
1743	    }
